import java.util.Scanner;

public class SecureBufferCopy {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Call the secure function to copy input into buffer
        secureCopyFunction(name);
    }

    public static void secureCopyFunction(String input) {
        int maxLength = 10; // Maximum length for buffer
        char[] buffer = new char[maxLength];

        // Copy the input into the buffer with proper length checking
        for (int i = 0; i < Math.min(input.length(), maxLength); i++) {
            buffer[i] = input.charAt(i);
        }

        System.out.println("Successfully copied user input into buffer: " + new String(buffer).trim());
    }
}

